<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    overflow: hidden;
    font-family: 'Segoe UI', Ubuntu, Cantarell, sans-serif;
    user-select: none;
    height: 100vh;
    width: 100vw;
  }

  #desktop {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(135deg, #2c001e 0%, #4a0033 30%, #1a1a2e 70%, #16213e 100%);
    display: flex;
    flex-direction: column;
    z-index: 0;
  }

  /* Top bar */
  #topbar {
    height: 28px;
    background: rgba(20, 20, 20, 0.95);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    color: #e0e0e0;
    font-size: 13px;
    z-index: 100;
    -webkit-app-region: drag;
  }

  #topbar .left { display: flex; align-items: center; gap: 6px; }
  #topbar .center { color: #aaa; font-size: 12px; letter-spacing: 0.3px; }
  #topbar .right { display: flex; align-items: center; gap: 14px; color: #ccc; font-size: 12px; }

  /* Taskbar / Dock */
  #taskbar {
    position: absolute;
    bottom: 0; left: 0; right: 0;
    height: 56px;
    background: rgba(30, 30, 30, 0.92);
    backdrop-filter: blur(12px);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    z-index: 90;
    border-top: 1px solid rgba(255,255,255,0.06);
  }

  .dock-btn {
    width: 44px; height: 44px;
    border-radius: 10px;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.2s ease;
    position: relative;
  }

  .dock-btn:hover { transform: scale(1.1); }
  .dock-btn:active { transform: scale(0.95); }

  #open-files { background: linear-gradient(135deg, #e67e22, #f39c12); }
  #open-notepad { background: linear-gradient(135deg, #3498db, #2980b9); }

  .dock-btn svg { width: 24px; height: 24px; fill: white; }

  /* Window base */
  .app-window {
    position: absolute;
    background: #2d2d2d;
    border-radius: 10px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,255,255,0.06);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-width: 380px;
    min-height: 280px;
    z-index: 50;
  }

  .app-window.hidden { display: none !important; }

  /* Window title bar */
  .win-titlebar {
    height: 36px;
    background: rgba(40, 40, 40, 0.98);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 10px;
    cursor: default;
    border-bottom: 1px solid rgba(255,255,255,0.04);
    -webkit-app-region: drag;
  }

  .win-titlebar .title {
    color: #ccc;
    font-size: 13px;
    font-weight: 500;
    display: flex;
    align-items: center;
    gap: 6px;
  }

  .win-titlebar .title svg { width: 14px; height: 14px; fill: #aaa; }

  .win-controls { display: flex; gap: 7px; -webkit-app-region: no-drag; }

  .win-btn {
    width: 20px; height: 20px;
    border-radius: 50%;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 10px;
    color: transparent;
    transition: all 0.15s;
  }

  .win-btn:hover { color: rgba(0,0,0,0.7); }

  #btn-minimize { background: #f39c12; }
  #btn-maximize { background: #2ecc71; }
  .win-close { background: #e74c3c; }

  /* Files window */
  #files-window { width: 680px; height: 460px; top: 60px; left: 100px; }

  #files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 12px;
    background: rgba(50, 50, 50, 0.9);
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }

  #files-up {
    width: 30px; height: 30px;
    border-radius: 6px;
    border: none;
    background: rgba(255,255,255,0.08);
    color: #ccc;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 16px;
    transition: background 0.15s;
  }

  #files-up:hover { background: rgba(255,255,255,0.15); }

  #files-path {
    flex: 1;
    height: 30px;
    background: rgba(0,0,0,0.3);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 6px;
    padding: 0 10px;
    color: #e0e0e0;
    font-size: 13px;
    display: flex;
    align-items: center;
    font-family: 'Ubuntu Mono', 'Consolas', monospace;
  }

  #files-content {
    flex: 1;
    padding: 8px;
    overflow-y: auto;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(90px, 1fr));
    gap: 6px;
    align-content: start;
  }

  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 10px 4px;
    border-radius: 8px;
    cursor: pointer;
    transition: background 0.15s;
    text-align: center;
    min-height: 70px;
  }

  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item:active { background: rgba(255,255,255,0.14); }

  .fs-item .icon { font-size: 32px; margin-bottom: 6px; line-height: 1; }
  .fs-item .name { color: #ddd; font-size: 11px; word-break: break-word; line-height: 1.3; max-width: 100%; }

  /* Notepad window */
  #notepad-window { width: 620px; height: 480px; top: 50px; left: 180px; }

  #notepad-toolbar {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 6px 12px;
    background: rgba(45, 45, 45, 0.95);
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }

  #new-tab {
    height: 28px;
    padding: 0 12px;
    border-radius: 5px;
    border: none;
    background: rgba(52, 152, 219, 0.8);
    color: white;
    font-size: 12px;
    cursor: pointer;
    transition: background 0.15s;
    display: flex;
    align-items: center;
    gap: 4px;
  }

  #new-tab:hover { background: rgba(52, 152, 219, 1); }

  #tabs {
    flex: 1;
    display: flex;
    gap: 3px;
    overflow-x: auto;
    align-items: center;
    min-height: 0;
  }

  .tab {
    height: 28px;
    padding: 0 14px;
    border-radius: 5px;
    background: rgba(255,255,255,0.06);
    color: #bbb;
    font-size: 12px;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 6px;
    white-space: nowrap;
    transition: all 0.15s;
    border: none;
    flex-shrink: 0;
  }

  .tab:hover { background: rgba(255,255,255,0.1); color: #ddd; }
  .tab.active { background: rgba(255,255,255,0.14); color: #fff; font-weight: 500; }

  .tab .close-tab {
    width: 16px; height: 16px;
    border-radius: 50%;
    border: none;
    background: transparent;
    color: #999;
    font-size: 10px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.15s;
  }

  .tab .close-tab:hover { background: rgba(231,76,60,0.8); color: white; }

  #editor-wrap {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
  }

  #editor {
    flex: 1;
    resize: none;
    border: none;
    outline: none;
    background: #232323;
    color: #e8e8e8;
    font-family: 'Ubuntu Mono', 'Consolas', 'Courier New', monospace;
    font-size: 14px;
    line-height: 1.6;
    padding: 14px;
    tab-size: 4;
  }

  /* Scrollbar */
  ::-webkit-scrollbar { width: 8px; height: 8px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.15); border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.25); }

  /* Dragging */
  .app-window.dragging { opacity: 0.85; transition: none; z-index: 999; }
</style>
</head>
<body>

<div id="desktop">
  <!-- Top Bar -->
  <div id="topbar">
    <div class="left">
      <span style="font-weight:600;">Activities</span>
    </div>
    <div class="center" id="clock"></div>
    <div class="right">
      <span>🔊</span>
      <span>📶</span>
      <span>🔋 87%</span>
    </div>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="app-window hidden">
    <div class="win-titlebar">
      <div class="title">
        <svg viewBox="0 0 24 24"><path d="M10 4H4c-1.1 0-2 .9-2 2v12c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/></svg>
        Files
      </div>
      <div class="win-controls">
        <button class="win-btn" id="btn-minimize">—</button>
        <button class="win-btn" id="btn-maximize">□</button>
        <button class="win-btn win-close">✕</button>
      </div>
    </div>
    <div id="files-toolbar">
      <button id="files-up">↑</button>
      <div id="files-path">/</div>
    </div>
    <div id="files-content"></div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="app-window hidden">
    <div class="win-titlebar">
      <div class="title">
        <svg viewBox="0 0 24 24"><path d="M14 2H6c-1.1 0-2 .9-2 2v16c0 1.1.9 2 2 2h12c1.1 0 2-.9 2-2V8l-6-6zm4 18H6V4h7v5h5v11z"/></svg>
        Notepad
      </div>
      <div class="win-controls">
        <button class="win-btn" id="btn-minimize-n">—</button>
        <button class="win-btn" id="btn-maximize-n">□</button>
        <button class="win-btn win-close">✕</button>
      </div>
    </div>
    <div id="notepad-toolbar">
      <button id="new-tab">＋ New Tab</button>
      <div id="tabs"></div>
    </div>
    <div id="editor-wrap">
      <textarea id="editor" spellcheck="false"></textarea>
    </div>
  </div>

  <!-- Taskbar / Dock -->
  <div id="taskbar">
    <button id="open-files" class="dock-btn" title="Files">
      <svg viewBox="0 0 24 24"><path d="M10 4H4c-1.1 0-2 .9-2 2v12c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/></svg>
    </button>
    <button id="open-notepad" class="dock-btn" title="Notepad">
      <svg viewBox="0 0 24 24"><path d="M14 2H6c-1.1 0-2 .9-2 2v16c0 1.1.9 2 2 2h12c1.1 0 2-.9 2-2V8l-6-6zm4 18H6V4h7v5h5v11z"/></svg>
    </button>
  </div>
</div>

<script>
(function() {
  'use strict';

  // ── Clock ──
  function updateClock() {
    const now = new Date();
    document.getElementById('clock').textContent = now.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' }) + '  ' + now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
  }
  updateClock();
  setInterval(updateClock, 10000);

  // ── Filesystem data ──
  const fs = {
    '/': {
      type: 'dir',
      children: ['bin', 'etc', 'home', 'usr', 'var']
    },
    '/bin': {
      type: 'dir',
      children: ['bash', 'cat', 'cp', 'ls', 'mkdir', 'mv', 'rm', 'sudo']
    },
    '/etc': {
      type: 'dir',
      children: ['passwd', 'hostname', 'fstab', 'hosts', 'network', 'ssh']
    },
    '/home': {
      type: 'dir',
      children: ['user']
    },
    '/home/user': {
      type: 'dir',
      children: ['Documents', 'Downloads', 'Pictures', '.bashrc', '.profile', 'Desktop']
    },
    '/home/user/Documents': {
      type: 'dir',
      children: ['notes.txt', 'todo.md', 'report.pdf']
    },
    '/home/user/Downloads': {
      type: 'dir',
      children: ['ubuntu.iso', 'archive.tar.gz', 'image.png']
    },
    '/home/user/Pictures': {
      type: 'dir',
      children: ['wallpaper.jpg', 'screenshot.png', 'vacation']
    },
    '/home/user/Pictures/vacation': {
      type: 'dir',
      children: ['beach.jpg', 'mountain.jpg', 'hotel.jpg']
    },
    '/home/user/Desktop': {
      type: 'dir',
      children: ['readme.txt']
    },
    '/usr': {
      type: 'dir',
      children: ['bin', 'lib', 'share', 'local']
    },
    '/usr/bin': {
      type: 'dir',
      children: ['python3', 'node', 'git', 'vim', 'nano']
    },
    '/usr/lib': {
      type: 'dir',
      children: ['libc.so', 'libssl.so', 'libz.so']
    },
    '/usr/share': {
      type: 'dir',
      children: ['man', 'doc', 'locale']
    },
    '/var': {
      type: 'dir',
      children: ['log', 'cache', 'tmp', 'www']
    },
    '/var/log': {
      type: 'dir',
      children: ['syslog', 'auth.log', 'kern.log']
    },
    '/var/cache': {
      type: 'dir',
      children: ['apt', 'pip']
    },
    '/var/www': {
      type: 'dir',
      children: ['html', 'cgi-bin']
    }
  };

  // Ensure all paths exist in fs object (for files)
  function ensurePath(path) { if (!fs[path]) fs[path] = { type: 'file' }; }
  // Mark file entries
  const filePaths = [
    '/bin/bash', '/bin/cat', '/bin/cp', '/bin/ls', '/bin/mkdir', '/bin/mv', '/bin/rm', '/bin/sudo',
    '/etc/passwd', '/etc/hostname', '/etc/fstab', '/etc/hosts', '/etc/network', '/etc/ssh',
    '/home/user/.bashrc', '/home/user/.profile',
    '/home/user/Documents/notes.txt', '/home/user/Documents/todo.md', '/home/user/Documents/report.pdf',
    '/home/user/Downloads/ubuntu.iso', '/home/user/Downloads/archive.tar.gz', '/home/user/Downloads/image.png',
    '/home/user/Pictures/wallpaper.jpg', '/home/user/Pictures/screenshot.png',
    '/home/user/Desktop/readme.txt',
    '/usr/bin/python3', '/usr/bin/node', '/usr/bin/git', '/usr/bin/vim', '/usr/bin/nano',
    '/usr/lib/libc.so', '/usr/lib/libssl.so', '/usr/lib/libz.so',
    '/var/log/syslog', '/var/log/auth.log', '/var/log/kern.log',
    '/var/cache/apt', '/var/cache/pip'
  ];
  filePaths.forEach(p => ensurePath(p));

  function getDir(path) { return fs[path] || null; }

  // ── Files app state ──
  let currentPath = '/';

  const filesWindow = document.getElementById('files-window');
  const filesContent = document.getElementById('files-content');
  const filesPathEl = document.getElementById('files-path');
  const filesUpBtn = document.getElementById('files-up');

  function renderFiles() {
    filesContent.innerHTML = '';
    const dir = getDir(currentPath);
    if (!dir || dir.type !== 'dir') return;

    for (const name of dir.children) {
      const childPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
      const child = getDir(childPath);
      const isDir = child && child.type === 'dir';

      const item = document.createElement('div');
      item.className = 'fs-item';
      item.innerHTML = '<span class="icon">' + (isDir ? '📁' : getFileIcon(name)) + '</span><span class="name">' + escapeHtml(name) + '</span>';

      let clickCount = 0;
      item.addEventListener('click', function() {
        clickCount++;
        if (clickCount === 1) {
          setTimeout(function() {
            if (clickCount === 1) { /* single click — could do something */ }
            clickCount = 0;
          }, 250);
        }
      });

      item.addEventListener('dblclick', function(e) {
        e.preventDefault();
        if (isDir) {
          currentPath = childPath;
          filesPathEl.textContent = currentPath;
          renderFiles();
        }
      });

      filesContent.appendChild(item);
    }
  }

  function getFileIcon(name) {
    const ext = name.split('.').pop().toLowerCase();
    if (['txt','md','log'].includes(ext)) return '📄';
    if (['pdf'].includes(ext)) return '📕';
    if (['jpg','jpeg','png','gif','iso'].includes(ext)) return '🖼️';
    if (['tar','gz','zip','rar'].includes(ext)) return '📦';
    if (['bash','sh'].includes(ext)) return '⚙️';
    return '📄';
  }

  function escapeHtml(s) {
    return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  }

  filesUpBtn.addEventListener('click', function() {
    if (currentPath === '/') return;
    const parts = currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath = '/' + parts.join('/') || '/';
    filesPathEl.textContent = currentPath;
    renderFiles();
  });

  // ── Notepad app state & persistence ──
  const STORAGE_KEY = 'notepad-tabs';

  function loadTabs() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) return JSON.parse(raw);
    } catch(e) {}
    return [];
  }

  function saveTabs(tabs) {
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs)); } catch(e) {}
  }

  let tabs = loadTabs();
  let activeTabIndex = -1;

  const notepadWindow = document.getElementById('notepad-window');
  const tabsContainer = document.getElementById('tabs');
  const editorEl = document.getElementById('editor');
  const newTabBtn = document.getElementById('new-tab');

  function initNotepad() {
    if (tabs.length === 0) {
      tabs.push({ name: 'Untitled', content: '' });
      activeTabIndex = 0;
      saveTabs(tabs);
    } else {
      activeTabIndex = Math.min(activeTabIndex, tabs.length - 1);
      if (activeTabIndex < 0) activeTabIndex = 0;
    }
    renderTabs();
    loadActiveContent();
  }

  function renderTabs() {
    tabsContainer.innerHTML = '';
    for (let i = 0; i < tabs.length; i++) {
      const t = document.createElement('button');
      t.className = 'tab' + (i === activeTabIndex ? ' active' : '');
      t.textContent = tabs[i].name || 'Untitled';

      const closeBtn = document.createElement('span');
      closeBtn.className = 'close-tab';
      closeBtn.innerHTML = '&#x2715;';
      closeBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        closeTab(i);
      });
      t.appendChild(closeBtn);

      t.addEventListener('click', function() {
        saveActiveContent();
        activeTabIndex = i;
        renderTabs();
        loadActiveContent();
      });

      tabsContainer.appendChild(t);
    }
  }

  function closeTab(index) {
    if (tabs.length <= 1) return; // keep at least one tab
    saveActiveContent();
    tabs.splice(index, 1);
    if (activeTabIndex >= tabs.length) activeTabIndex = tabs.length - 1;
    saveTabs(tabs);
    renderTabs();
    loadActiveContent();
  }

  function saveActiveContent() {
    if (activeTabIndex >= 0 && activeTabIndex < tabs.length) {
      tabs[activeTabIndex].content = editorEl.value;
      saveTabs(tabs);
    }
  }

  function loadActiveContent() {
    if (activeTabIndex >= 0 && activeTabIndex < tabs.length) {
      editorEl.value = tabs[activeTabIndex].content || '';
    }
  }

  newTabBtn.addEventListener('click', function() {
    saveActiveContent();
    const idx = tabs.length;
    tabs.push({ name: 'Untitled', content: '' });
    activeTabIndex = idx;
    saveTabs(tabs);
    renderTabs();
    loadActiveContent();
  });

  // Auto-save on typing (debounced)
  let saveTimeout;
  editorEl.addEventListener('input', function() {
    clearTimeout(saveTimeout);
    saveTimeout = setTimeout(function() {
      if (activeTabIndex >= 0 && activeTabIndex < tabs.length) {
        tabs[activeTabIndex].content = editorEl.value;
        saveTabs(tabs);
      }
    }, 500);
  });

  // ── Window management ──
  function showWindow(winId, dockBtnId) {
    const win = document.getElementById(winId);
    win.classList.remove('hidden');
    bringToFront(win);
  }

  function hideWindow(winId) {
    const win = document.getElementById(winId);
    win.classList.add('hidden');
  }

  let highestZ = 50;

  function bringToFront(win) {
    highestZ++;
    win.style.zIndex = highestZ;
  }

  // Dock buttons
  document.getElementById('open-files').addEventListener('click', function() {
    showWindow('files-window');
    renderFiles();
  });

  document.getElementById('open-notepad').addEventListener('click', function() {
    showWindow('notepad-window');
    initNotepad();
  });

  // Close buttons (any .win-close)
  document.querySelectorAll('.win-close').forEach(function(btn) {
    btn.addEventListener('click', function() {
      const win = btn.closest('.app-window');
      if (win) hideWindow(win.id);
    });
  });

  // Minimize / Maximize buttons (basic)
  document.getElementById('btn-minimize').addEventListener('click', function() {
    const win = filesWindow;
    if (win.dataset.minimized === 'true') {
      win.classList.remove('hidden');
      win.style.height = '';
      win.dataset.minimized = 'false';
    } else {
      win.dataset.minimized = 'true';
      win.style.height = '36px';
    }
  });

  document.getElementById('btn-maximize').addEventListener('click', function() {
    const win = filesWindow;
    if (win.dataset.maximized === 'true') {
      win.classList.remove('hidden');
      win.style.top = '60px';
      win.style.left = '100px';
      win.style.width = '680px';
      win.style.height = '460px';
      win.dataset.maximized = 'false';
    } else {
      win.classList.remove('hidden');
      win.style.top = '28px';
      win.style.left = '0';
      win.style.width = '100vw';
      win.style.height = 'calc(100vh - 56px)';
      win.dataset.maximized = 'true';
    }
  });

  document.getElementById('btn-minimize-n').addEventListener('click', function() {
    const win = notepadWindow;
    if (win.dataset.minimized === 'true') {
      win.classList.remove('hidden');
      win.style.height = '';
      win.dataset.minimized = 'false';
    } else {
      win.dataset.minimized = 'true';
      win.style.height = '36px';
    }
  });

  document.getElementById('btn-maximize-n').addEventListener('click', function() {
    const win = notepadWindow;
    if (win.dataset.maximized === 'true') {
      win.classList.remove('hidden');
      win.style.top = '50px';
      win.style.left = '180px';
      win.style.width = '620px';
      win.style.height = '480px';
      win.dataset.maximized = 'false';
    } else {
      win.classList.remove('hidden');
      win.style.top = '28px';
      win.style.left = '0';
      win.style.width = '100vw';
      win.style.height = 'calc(100vh - 56px)';
      win.dataset.maximized = 'true';
    }
  });

  // ── Dragging windows ──
  function makeDraggable(win) {
    const titlebar = win.querySelector('.win-titlebar');
    let offsetX, offsetY, isDragging = false;

    titlebar.addEventListener('mousedown', function(e) {
      if (e.target.closest('.win-controls') || e.target.closest('#files-toolbar') || e.target.closest('#notepad-toolbar')) return;
      if (win.dataset.maximized === 'true') return;
      isDragging = true;
      offsetX = e.clientX - win.offsetLeft;
      offsetY = e.clientY - win.offsetTop;
      bringToFront(win);
      win.classList.add('dragging');
      e.preventDefault();
    });

    document.addEventListener('mousemove', function(e) {
      if (!isDragging) return;
      let nx = e.clientX - offsetX;
      let ny = e.clientY - offsetY;
      // Clamp to viewport
      ny = Math.max(28, ny);
      win.style.left = nx + 'px';
      win.style.top = ny + 'px';
    });

    document.addEventListener('mouseup', function() {
      if (isDragging) {
        isDragging = false;
        win.classList.remove('dragging');
      }
    });

    // Click to bring to front
    win.addEventListener('mousedown', function() {
      bringToFront(win);
    });
  }

  makeDraggable(filesWindow);
  makeDraggable(notepadWindow);

  // ── Init files app on first open ──
  renderFiles();

})();
